#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *F = (long long*)malloc(sizeof(long long)*N);
        for(int i=0;i<N;i++) scanf("%lld", &F[i]);
        int ok = 1; // all previous frequencies >0
        for(int i=0;i<=N;i++){
            long long ans;
            if(i==0){
                ans = F[0];
            }else if(i==N){
                ans = ok ? 0 : -1;
            }else{
                if(ok && F[i-1]>0) ans = F[i];
                else ans = -1;
            }
            if(i) printf(" ");
            printf("%lld", ans);
            if(i<N) ok = ok && (F[i]>0);
        }
        printf("\n");
        free(F);
    }
    return 0;
}

