#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        F = [int(next(it)) for _ in range(N)]
        ok = True
        ans = []
        for i in range(N+1):
            if i == 0:
                cur = F[0]
            elif i == N:
                cur = 0 if ok else -1
            else:
                cur = F[i] if ok and F[i-1] > 0 else -1
            ans.append(str(cur))
            if i < N:
                ok = ok and (F[i] > 0)
        out_lines.append(' '.join(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

